using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9]+$", ErrorMessage = "Student ID must be alphanumeric.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and rhetoric." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and civilizations." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, methods, and object-oriented programming basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Alice Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and education. She holds a Ph.D. from MIT and has published extensively on programming pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. Bob Martinez", InstructorBio = "Dr. Martinez specializes in algorithm optimization and has contributed to open-source projects used by millions of developers worldwide.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Design and implementation of relational databases, SQL, normalization, transaction processing, and introduction to NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Carol Nguyen", InstructorBio = "Dr. Nguyen spent a decade at Oracle before joining academia. Her research focuses on distributed database architectures.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. David Park", InstructorBio = "Dr. Park is a mathematician specializing in analysis. He has received multiple teaching excellence awards.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to computer graphics and data science.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Foster", InstructorBio = "Dr. Foster's research bridges pure mathematics and machine learning applications.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Code = "ENG 101", Title = "College Writing", Description = "Develop critical reading and academic writing skills. Focus on argumentation, research methods, and clear prose.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Prof. Frank Hughes", InstructorBio = "Prof. Hughes is a published author and writing coach with expertise in rhetoric and composition studies.", DepartmentId = 3, DepartmentName = "English", IsFeatured = false },
            new() { Id = 7, Code = "ENG 220", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present, exploring themes of identity, democracy, and culture.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Grace Kim", InstructorBio = "Dr. Kim is a scholar of 20th-century American fiction and has authored two books on the Harlem Renaissance.", DepartmentId = 3, DepartmentName = "English", IsFeatured = true },
            new() { Id = 8, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory component with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed 8:00–9:15 AM, Lab: Fri 1:00–3:00 PM", InstructorName = "Dr. Henry Wallace", InstructorBio = "Dr. Wallace is an experimental physicist whose work on quantum optics has been featured in Nature and Science.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, Code = "PHYS 250", Title = "Modern Physics", Description = "Introduction to special relativity, quantum mechanics, atomic structure, and nuclear physics.", Credits = 3, Schedule = "Tue/Thu 2:30–3:45 PM", InstructorName = "Dr. Irene Patel", InstructorBio = "Dr. Patel researches particle physics and has collaborated on experiments at CERN.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 10, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, trade networks, and cultural exchanges from prehistory through the medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. James Okafor", InstructorBio = "Dr. Okafor specializes in comparative ancient civilizations and has conducted fieldwork across three continents.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
}

