﻿@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-4">Welcome to the University Course Catalog</h1>
    <p class="lead text-muted">Browse courses, explore departments, and enroll today.</p>
    <a href="/courses" class="btn btn-primary btn-lg me-2">Browse All Courses</a>
    <a href="/enroll" class="btn btn-outline-primary btn-lg">Enroll Now</a>
</div>

<section class="mb-5">
    <h2>Featured Courses</h2>
    <div class="row">
        @foreach (var course in featuredCourses)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@course.Code</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                        <p class="card-text">@course.Credits credits &middot; @course.DepartmentName</p>
                        <a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

<section>
    <h2>Departments</h2>
    <div class="row">
        @foreach (var dept in departments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@dept.Name</h5>
                        <p class="card-text">@dept.Description</p>
                        <a href="/courses?departmentId=@dept.Id" class="btn btn-sm btn-outline-secondary">View Courses</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetAllDepartments();
    }
}

