@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p class="text-muted">Submit your enrollment request below. You will receive a confirmation once processed.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@courses.FirstOrDefault(c => c.Id == Model.CourseId)?.Title</strong> has been received.</p>
        <hr />
        <p class="mb-0">Student ID: @Model.StudentId</p>
    </div>
    <a href="/enroll" class="btn btn-primary">Submit Another Request</a>
}
else
{
    <div class="row">
        <div class="col-lg-8">
            <form method="post" @formname="enrollment">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
                    @if (errors.ContainsKey(nameof(Model.StudentName)))
                    {
                        <div class="text-danger small">@errors[nameof(Model.StudentName)]</div>
                    }
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" required />
                    @if (errors.ContainsKey(nameof(Model.StudentId)))
                    {
                        <div class="text-danger small">@errors[nameof(Model.StudentId)]</div>
                    }
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select id="courseId" name="Model.CourseId" class="form-select" required>
                        <option value="0">-- Select a Course --</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id" selected="@(course.Id == Model.CourseId)">@course.Code - @course.Title</option>
                        }
                    </select>
                    @if (errors.ContainsKey(nameof(Model.CourseId)))
                    {
                        <div class="text-danger small">@errors[nameof(Model.CourseId)]</div>
                    }
                </div>

                <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private Dictionary<string, string> errors = new();

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        if (HttpMethods.IsPost(HttpContextAccessor?.HttpContext?.Request.Method ?? ""))
        {
            // Validate
            errors.Clear();
            var validationResults = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
            var context = new System.ComponentModel.DataAnnotations.ValidationContext(Model);
            if (!System.ComponentModel.DataAnnotations.Validator.TryValidateObject(Model, context, validationResults, true))
            {
                foreach (var result in validationResults)
                {
                    foreach (var member in result.MemberNames)
                    {
                        if (!errors.ContainsKey(member))
                            errors[member] = result.ErrorMessage ?? "Invalid";
                    }
                }
            }
            else
            {
                submitted = true;
            }
        }
    }

    [CascadingParameter] public HttpContext? HttpContextAccessor { get; set; }
}

